  var properties = {};
  for (var i = 0; i < classes.length; i++) {
    var classDecl = classes[i].trim();
    if (classDecl.indexOf('{') !== -1) {
      var className = classDecl.substring(0, classDecl.indexOf('{')).trim();
      properties[className] = properties[className] || {};
