      var propDecl = props.split(';');
      for (var j = 0; j < propDecl.length; j++) {
        var prop = propDecl[j].trim();
        if (prop.indexOf(':') !== -1) {
          var propName = prop.substring(0, prop.indexOf(':')).trim();
          var propValue = prop.substring(prop.indexOf(':') + 1).trim();
          if (className in properties) {
            properties[className][propName] = propValue;
          } else {
            properties[className] = {[propName]: propValue};
          }
        }
      }
    }
  }
  var correctedCssString = '';
  for (var i = 0; i < classes.length; i++) {
    var classDecl = classes[i].trim();
